INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27341,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:9:\"WordPress\";s:11:\"policy_text\";s:4509:\"<h2 class=\"wp-block-heading\">Who we are</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Our website address is: https://staging-bf5f-antiviruspointorgdomainonly.wpcomstaging.com.</p><h2 class=\"wp-block-heading\">Comments</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p><p>An anonymized string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service privacy policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p><h2 class=\"wp-block-heading\">Media</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p><h2 class=\"wp-block-heading\">Cookies</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment on our site you may opt-in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p><p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p><p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p><p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p><h2 class=\"wp-block-heading\">Embedded content from other websites</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p><p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p><h2 class=\"wp-block-heading\">Who we share your data with</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you request a password reset, your IP address will be included in the reset email.</p><h2 class=\"wp-block-heading\">How long we retain your data</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognize and approve any follow-up comments automatically instead of holding them in a moderation queue.</p><p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p><h2 class=\"wp-block-heading\">What rights you have over your data</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p><h2 class=\"wp-block-heading\">Where your data is sent</h2><p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Visitor comments may be checked through an automated spam detection service.</p>\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27342,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:11:\"WooCommerce\";s:11:\"policy_text\";s:4106:\"<div class=\"wp-suggested-text\"><p class=\"privacy-policy-tutorial\">This sample language includes the basics around what personal data your store may be collecting, storing and sharing, as well as who may have access to that data. Depending on what settings are enabled and which additional plugins are used, the specific information shared by your store will vary. We recommend consulting with a lawyer when deciding what information to disclose on your privacy policy.</p><p>We collect information about you during the checkout process on our store.</p><h2>What we collect and store</h2><p>While you visit our site, we’ll track:</p><ul><li>Products you’ve viewed: we’ll use this to, for example, show you products you’ve recently viewed</li><li>Location, IP address and browser type: we’ll use this for purposes like estimating taxes and shipping</li><li>Shipping address: we’ll ask you to enter this so we can, for instance, estimate shipping before you place an order, and send you the order!</li></ul><p>We’ll also use cookies to keep track of cart contents while you’re browsing our site.</p><p class=\"privacy-policy-tutorial\">Note: you may want to further detail your cookie policy, and link to that section from here.</p><p>When you purchase from us, we’ll ask you to provide information including your name, billing address, shipping address, email address, phone number, credit card/payment details and optional account information like username and password. We’ll use this information for purposes, such as, to:</p><ul><li>Send you information about your account and order</li><li>Respond to your requests, including refunds and complaints</li><li>Process payments and prevent fraud</li><li>Set up your account for our store</li><li>Comply with any legal obligations we have, such as calculating taxes</li><li>Improve our store offerings</li><li>Send you marketing messages, if you choose to receive them</li></ul><p>If you create an account, we will store your name, address, email and phone number, which will be used to populate the checkout for future orders.</p><p>We generally store information about you for as long as we need the information for the purposes for which we collect and use it, and we are not legally required to continue to keep it. For example, we will store order information for XXX years for tax and accounting purposes. This includes your name, email address and billing and shipping addresses.</p><p>We will also store comments or reviews, if you choose to leave them.</p><h2>Who on our team has access</h2><p>Members of our team have access to the information you provide us. For example, both Administrators and Shop Managers can access:</p><ul><li>Order information like what was purchased, when it was purchased and where it should be sent, and</li><li>Customer information like your name, email address, and billing and shipping information.</li></ul><p>Our team members have access to this information to help fulfill orders, process refunds and support you.</p><h2>What we share with others</h2><p class=\"privacy-policy-tutorial\">In this section you should list who you’re sharing data with, and for what purpose. This could include, but may not be limited to, analytics, marketing, payment gateways, shipping providers, and third party embeds.</p><p>We share information with third parties who help us provide our orders and store services to you; for example --</p><h3>Payments</h3><p class=\"privacy-policy-tutorial\">In this subsection you should list which third party payment processors you’re using to take payments on your store since these may handle customer data. We’ve included PayPal as an example, but you should remove this if you’re not using PayPal.</p><p>We accept payments through PayPal. When processing payments, some of your data will be passed to PayPal, including information required to process or support the payment, such as the purchase total and billing information.</p><p>Please see the <a href=\"https://www.paypal.com/us/webapps/mpp/ua/privacy-full\">PayPal Privacy Policy</a> for more details.</p></div>\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27343,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:22:\"Easy Digital Downloads\";s:11:\"policy_text\";s:1393:\"<p>We collect information about you during the checkout process on our store. This information may include, but is not limited to, your name, billing address, shipping address, email address, phone number, credit card/payment details and any other details that might be requested from you for the purpose of processing your orders.<br />\nHandling this data also allows us to:<br />\n- Send you important account/order/service information.<br />\n- Respond to your queries, refund requests, or complaints.<br />\n- Process payments and to prevent fraudulent transactions. We do this on the basis of our legitimate business interests.<br />\n- Set up and administer your account, provide technical and/or customer support, and to verify your identity.</p>\n<p>Additionally we may also collect the following information:<br />\n- Location and traffic data (including IP address and browser type) if you place an order, or if we need to estimate taxes and shipping costs based on your location.<br />\n- Product pages visited and content viewed while your session is active.<br />\n- Your comments and product reviews if you choose to leave them on our website.<br />\n- Account email/password to allow you to access your account, if you have one.<br />\n- If you choose to create an account with us, your name, address, and email address, which will be used to populate the checkout for future orders.</p>\n\";s:5:\"added\";i:1755561659;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27344,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:27:\"WooCommerce Product Bundles\";s:11:\"policy_text\";s:136:\"\n			<div contenteditable=\"false\"><p class=\"wp-policy-help\">Product Bundles does not collect, store or share any personal data.</p></div>\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27345,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:35:\"WooCommerce Product Recommendations\";s:11:\"policy_text\";s:1280:\"\n			<div class=\"wp-suggested-text\"><p class=\"privacy-policy-tutorial\">WooCommerce Product Recommendations uses cookies to track the following visitor activity:</p><ul style=\"list-style:lower-roman;margin-left:20px;\"><li>Viewed products.</li><li>Viewed recommendations.</li><li>Clicked products in recommendations.</li></ul><p class=\"privacy-policy-tutorial\">The extension also stores aggregate information based on the recommendations that visitors view and click while browsing your site. This information cannot be used to personally identify any visitor.</p><p class=\"privacy-policy-tutorial\">Please make sure that your cookie and analytics policies are updated to reflect this information.</p><h3>Cookies</h3><p><strong>Suggested text:</strong> While browsing our site, we will set temporary cookies to track:</p><ul style=\"font-style:italic;list-style:lower-roman;margin-left:20px;\"><li>Recommendations you have viewed.</li><li>Product recommendations you have clicked.</li></ul><p>These cookies contain no personal data and expire after 1 day.</p><h3>Analytics</h3><p><strong>Suggested text:</strong> We store aggregate information based on the recommendations you view and click while browsing our site. This information cannot be used to personally identify you.</p></div>\";s:5:\"added\";i:1755561659;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27346,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:12:\"YITH Plugins\";s:11:\"policy_text\";s:2175:\"<div class=\"wp-suggested-text\">\n	\n	<p class=\"privacy-policy-tutorial\">This sample language includes the basics around what personal data your store may be collecting, storing and sharing, as well as who may have access to that data. Depending on what settings are enabled and which additional plugins are used, the specific information shared by your store will vary. We recommend consulting with a lawyer when deciding what information to disclose on your privacy policy.</p><h2>What we collect and store</h2><p class=\'privacy-policy-tutorial\'><strong>YITH WooCommerce Wishlist</strong></p><p>While you visit our site, we’ll track:</p><ul><li>Products you’ve added to the wishlist: we’ll use this to show you and other users your favourite products, and to create targeted email campaigns.</li><li>Wishlists you’ve created: we’ll keep track of the wishlists you create, and make them visible to the store staff</li></ul><p>We’ll also use cookies to keep track of wishlist contents while you’re browsing our site.</p><p class=\'privacy-policy-tutorial\'><strong>YITH WooCommerce Ajax Search Premium</strong></p><p>When you type a keyword in the search form the following information will be stored:</p><ul><li>Your customer ID and the query strings you type in the search form.</li></ul><p>We&#039;ll use this information for purposes, such as:</p><ul><li>Tracking the query string to make search analytics and to show you the chronology of your searches.</li></ul><p>We generally store information about you for as long as we need the information for the purposes for which we collect and use it, and as long as we are not legally required to continue to keep it.</p><h2>Who on our team has access</h2><p class=\'privacy-policy-tutorial\'><strong>YITH WooCommerce Wishlist</strong></p><p>Members of our team have access to the information you provide us with. For example, both Administrators and Shop Managers can access:</p><ul><li>Wishlist details, such as products added, date of addition, name and privacy settings of your wishlists</li></ul><p>Our team members have access to this information to offer you better deals for the products you love.</p>\n	</div>\n\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27347,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:25:\"MailChimp for WooCommerce\";s:11:\"policy_text\";s:307:\"<p>When shopping, we keep a record of your email and the cart contents for up to 30 days on our server. This record is kept to repopulate the contents of your cart if you switch devices or needed to come back another day. Read our privacy policy <a href=\"https://mailchimp.com/legal/privacy/\">here</a>.</p>\n\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27348,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:22:\"Google for WooCommerce\";s:11:\"policy_text\";s:449:\"<p class=\"privacy-policy-tutorial\">By using this extension, you may be storing personal data or sharing data with an external service. <a href=\"https://support.google.com/adspolicy/answer/54817\" target=\"_blank\">Learn more about what data is collected by Google and what you may want to include in your privacy policy</a>.</p>\n<style>#privacy-settings-accordion-block-google-listings-ads .privacy-settings-accordion-actions { display: none }</style>\n\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27349,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:15:\"Product Add-ons\";s:11:\"policy_text\";s:314:\"<p>By using this extension, you may be storing personal data or sharing data with an external service. <a href=\"https://woocommerce.com/document/marketplace-privacy/#woocommerce-product-addons\" target=\"_blank\">Learn more about how this works, including what you may want to include in your privacy policy.</a></p>\n\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27350,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:15:\"WooCommerce Tax\";s:11:\"policy_text\";s:305:\"<p>By using this extension, you may be storing personal data or sharing data with external services. <a href=\"https://jetpack.com/support/for-your-privacy-policy/#woocommerce-services\" target=\"_blank\">Learn more about how this works, including what you may want to include in your privacy policy.</a></p>\n\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27351,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:17:\"Shipment Tracking\";s:11:\"policy_text\";s:319:\"<p>By using this extension, you may be storing personal data or sharing data with an external service. <a href=\"https://docs.woocommerce.com/document/privacy-shipping/#woocommerce-shipment-tracking\" target=\"_blank\">Learn more about how this works, including what you may want to include in your privacy policy.</a></p>\n\";s:5:\"added\";i:1755561659;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27352,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:11:\"AutomateWoo\";s:11:\"policy_text\";s:5648:\"<div class=\"wp-suggested-text\">\n	<h2>How we use your data</h2>\n	<p class=\"privacy-policy-tutorial\">\n		AutomateWoo uses personal data in many of its features and stores personal data in your WordPress database. We do not store any personal data from your website on our servers. You may need to adjust the suggested text below based on your settings and which workflows are in use.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 If you opt-in to receive marketing updates we may use your personal information to provide you with product updates or marketing communications that we believe may be of interest to you. Personal data may also be used by our internal system to automate processes of our store.	</p>\n\n	<h2>What we collect and store</h2>\n\n	<h3>Cookies</h3>\n	<p class=\"privacy-policy-tutorial\">\n		AutomateWoo uses three cookies to enable the session and cart tracking features of the plugin. If you have these features enabled you should include these cookies in your policy. You should also mention whether the user must give consent before these cookies are set.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We use cookies to remember who you are when browsing our site and to store the contents of your cart for the purpose of reminding you. These cookies will only be set when you consent to allowing additional cookies on our website.	</p>\n	<p>\n		<strong>wp_automatewoo_visitor</strong> - Used to store a secure key that is unique to you - Expires after 2 years		<br>\n		<strong>wp_automatewoo_session_started</strong> - Used to flag when you begin interacting with our website - Expires when you end the browser session		<br>\n		<strong>automatewoo_do_cart_update</strong> - Used to store flag when your stored cart needs to be updated - Expires when you end the browser session	</p>\n\n	<h3>Carts</h3>\n	<p class=\"privacy-policy-tutorial\">\n		If you are using AutomateWoo&#039;s cart tracking feature user carts will be stored for 60 days, depending on your settings.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We store a copy of your cart in our database for 60 days for the purpose of reminding you when your cart is abandoned.	</p>\n\n	<h3>Communication preferences</h3>\n	<p class=\"privacy-policy-tutorial\">\n		AutomateWoo keeps a record of when a user or guest chooses to opt-in or opt-out.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We store your communication preferences such as whether you have opted in to receive marketing communication. This data is retained until you request the removal of your data.	</p>\n\n	<h3>Communication logs</h3>\n	<p class=\"privacy-policy-tutorial\">\n		AutomateWoo keeps a record of all workflow logs which includes open, click and conversion tracking.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We keep a log of some of the communication that we have with you which may include marketing and transactional emails and/or SMS messages. These are kept for the purpose of improving our marketing and communication with you and other customers. These logs are retained until you request removal of your data.	</p>\n\n	<h3>Pre-submit data capture</h3>\n	<p class=\"privacy-policy-tutorial\">\n		AutomateWoo has the option to capture customer data before forms are submitted which usually means that consent has not been given. Using this feature may not be legal in some regions depending on your legal basis for capturing that data. If you choose to use this feature we recommend including some reasoning behind it.	</p>\n\n	<h2>What we share with others</h2>\n	<p class=\"privacy-policy-tutorial\">\n		AutomateWoo integrates with third party services which means personal data may be shared depending on what integrations you have enabled and which workflows you are using.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We use Twilio as our SMS delivery service. Your data may be transferred to Twilio for processing in accordance with their <a href=\"https://www.twilio.com/legal/privacy\" target=\"_blank\">Privacy Policy</a>.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We use MailChimp for email marketing. Your data may be transferred to MailChimp for processing in accordance with their <a href=\"https://mailchimp.com/legal/privacy\" target=\"_blank\">Privacy Policy</a>.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We use Active Campaign for email marketing. Your data may be transferred to Active Campaign for processing in accordance with their <a href=\"https://www.activecampaign.com/privacy-policy\" target=\"_blank\">Privacy Policy</a>.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We use Campaign Monitor for email marketing. Your data may be transferred to Campaign Monitor for processing in accordance with their <a href=\"https://www.campaignmonitor.com/policies/#privacy-policy\" target=\"_blank\">Privacy Policy</a>.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We use Bitly for link shortening. Your data may be transferred to Bitly for processing in accordance with their <a href=\"https://bitly.com/pages/privacy\" target=\"_blank\">Privacy Policy</a>.	</p>\n	<p>\n				<strong class=\"privacy-policy-tutorial\">Suggested text:</strong>\n		 We use AgileCRM as our CRM. Your data may be transferred to AgileCRM for processing in accordance with their <a href=\"https://www.agilecrm.com/privacy-policy\" target=\"_blank\">Privacy Policy</a>.	</p>\n</div>\n		\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27353,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:7:\"Akismet\";s:11:\"policy_text\";s:400:\"We collect information about visitors who comment on Sites that use our Akismet Anti-spam service. The information we collect depends on how the User sets up Akismet for the Site, but typically includes the commenter\'s IP address, user agent, referrer, and Site URL (along with other information directly provided by the commenter such as their name, username, email address, and the comment itself).\";s:5:\"added\";i:1751489748;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27354,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:12:\"Activity Log\";s:11:\"policy_text\";s:113:\"<p>If you are a registered user, we save your content activity like create/update/delete posts and comments.</p>\n\";s:5:\"added\";i:1756228457;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27355,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:25:\"WooCommerce Subscriptions\";s:11:\"policy_text\";s:970:\"<p>By using WooCommerce Subscriptions, you may be storing personal data and depending on which third-party payment processors you’re using to take subscription payments, you may be sharing personal data with external sources.</p><h3>What we collect and store</h3><p>For the purposes of processing recurring subscription payments, we store the customer\'s name, billing address, shipping address, email address, phone number and credit card/payment details.</p><h3>What we share with others</h3><p>What personal information your store shares with external sources depends on which third-party payment processor plugins you are using to collect subscription payments. We recommend that you consult with their privacy policies to inform this section of your privacy policy.</p><p>If you are using PayPal Standard or PayPal Reference transactions please see the <a href=\"https://www.paypal.com/us/webapps/mpp/ua/privacy-full\">PayPal Privacy Policy</a> for more details.</p>\";s:5:\"added\";i:1756228457;}');
INSERT INTO `fqsi_postmeta` (`meta_id`, `post_id`, `meta_key`, `meta_value`) VALUES (27356,14,'_wp_suggested_privacy_policy_content','a:3:{s:11:\"plugin_name\";s:20:\"WooCommerce Shipping\";s:11:\"policy_text\";s:305:\"<p>By using this extension, you may be storing personal data or sharing data with external services. <a href=\"https://jetpack.com/support/for-your-privacy-policy/#woocommerce-shipping\" target=\"_blank\">Learn more about how this works, including what you may want to include in your privacy policy.</a></p>\n\";s:7:\"removed\";i:1756228457;}');
